---@return LStoryEventBase
function LStoryEventCtrl:GetStoryEvent(eventData,curTime)
    local eventType = eventData.eventType
    local event = nil
    if self._spineEvents[eventType] then
        event = LStorySpineEvent:New(self._manager)
    elseif self._effectEvents[eventType] then
        event = LStoryEffectEvent:New(self._manager)
    elseif self._cameraEvents[eventType] then
        event = LStoryCameraEvent:New(self._manager)
    elseif self._uiEvents[eventType] then
        event = LStoryUIEvent:New(self._manager)
    elseif eventType == LStoryEventType.START_AI then
        event = LStoryAiEvent:New(self._manager)
    elseif eventType == LStoryEventType.EVENT_CLEAR then
        event = LStoryClearEvent:New(self._manager)
    elseif eventType == LStoryEventType.PLAY_BATTLE then
        event = LStoryBattleEvent:New(self._manager)
    elseif eventType == LStoryEventType.EFFECT_BUFF then
        event = LStoryBuffEvent:New(self._manager)
    end

    if event then
        event:Create(eventData,curTime)
    end
    return event
end

function LStoryEventCtrl:FormatEventTimeLine(startId,curTime)
    local endEventData = nil
    local eventDataList = {}
    local cfg = gModelPlot:GetStorySceneRef(startId)
    if not cfg then
        return eventDataList,endEventData
    end

    local showSkip = cfg.storyJump
    local list = gModelPlot:GetStoryEventSimpleList(startId)
    local data = {
        groupId  = startId,
        startTime = curTime,
        startDelay = 0,
        eventList = list,
        condition = nil,
        showSkip = showSkip
    }

    local storyEnd = cfg.storyEnd
    if not string.isempty(storyEnd) then
        endEventData = data
    end
    table.insert(eventDataList,data)
    local curId = cfg.next
    local condition = cfg.reset
    local tempDelay = cfg.nextTime

    local idMap = {}
    while (curId > 0) do
        if idMap[curId] then
            printErrorN("loop id")
            break
        end
        idMap[curId] = true
        local tempCfg = gModelPlot:GetStorySceneRef(curId)
        if not tempCfg then
            printErrorN(string.format("no StorySceneRef %s ",curId))
            break
        end

        local tempEventList = gModelPlot:GetStoryEventSimpleList(curId)
        showSkip = tempCfg.storyJump
        local mapName = tempCfg.storyScene
        local guideId = tempCfg.guideId
        local data = {
            groupId = curId,
            startTime =0,
            startDelay = tempDelay,--延迟时间
            eventList = tempEventList,
            condition = condition,
            showSkip = showSkip,
            mapName = mapName,
            guideId = tonumber(guideId),
        }

        local storyEnd = tempCfg.storyEnd
        if not string.isempty(storyEnd) then
            endEventData = data
        end

        table.insert(eventDataList,data)
        curId = tempCfg.next
        condition = tempCfg.reset
        tempDelay = tempCfg.nextTime
    end
    return eventDataList,endEventData
end


function LStoryEventCtrl:InitStoryEvent(storyId)
    self._storyId = storyId
    local curTime = self:GetManager():GetTime()
    local eventDataList,endEventData = self:FormatEventTimeLine(self._storyId,curTime)
    if not self._eventDataList then
        self._eventDataList = eventDataList
    else
        for k,v in ipairs(eventDataList) do
            table.insert(self._eventDataList,v)
        end
    end

    self._endEventData = endEventData
end

function LStoryEventCtrl:GetStoryId()
	return self._storyId
end

function LStoryEventCtrl:CheckStartEvent(time)
    local curTime = time
    local list = self._storyEventList or {}
    local eventMap = self._storyEventMap or {}
    local first = self._eventDataList[1]
    if not first then
        return
    end

    if first.startTime > time then
        return
    end

    local isAllow = self:CheckCondition(first.condition)
    if not isAllow then
        return
    end
	self._storyId = first.groupId

    if first.guideId then
        gModelGuide:StartGuide(first.guideId)
    end
	
	--gLxTKData:OnStoryStep(first.groupId)
    gModelPlot:OnSceneSystemLookReq(first.groupId)

    local isEnd = false
    for k,v in ipairs(first.eventList) do
        local event = self:GetStoryEvent(v,curTime)
        if event then
            table.insert(list,event)
            local eventId = event:GetEventId()
            eventMap[eventId] = event
        end

        isEnd = v.eventType == LStoryEventType.BLACK_END
    end

    if not string.isempty(first.mapName) then
        self._manager:ChangeMap(first.mapName)
    end
    if LOG_INFO_ENABLED then
        printInfoN("start group id "..first.groupId)
    end


    GF.OpenWnd("UISy",{operType = 3 , para = first.showSkip})

    self._storyEventList = list
    self._storyEventMap = eventMap

    table.remove(self._eventDataList,1)

    local next = self._eventDataList[1]
    if next then
        next.startTime = next.startDelay+ curTime
    end

    if isEnd then
        local ref = gModelPlot:GetStorySceneRef(first.groupId)
        if ref then
            local storyEnd = ref.storyEnd
            local paras = LxDataHelper.ParseNumber_Sign(storyEnd,"=")
            self._manager:OnAllEventEnd(paras)
        end
    end
end

function LStoryEventCtrl:CheckEndEvent()
    if not self._endEventData then
        return
    end

    local isEnd = true
    for k,v in pairs(self._endEventData.eventList) do
        local event = self._storyEventMap[v.eventId]
        if not event then
            isEnd = false
            break
        end

        if not event:IsLoop() and not event:IsEnd() then
            isEnd = false
            break
        end
    end

    if isEnd then
        self:GetManager():StopStory()
        GF.CloseWndByName("UISy")
    end

end

function LStoryEventCtrl:CheckCondition(condition)
    if string.isempty(condition) then
        return true
    end

    local paras = LxDataHelper.ParseNumber_Sign(condition,"=")
    local type = paras[1]
    local para = paras[2]


    local objCtrl = self._manager:GetObjCtrl()

    if type == 1 then
        local event = self._storyEventMap[para]
        if event then
            return event:IsEnd()
        end
    elseif type == 2 then
        local isDead = objCtrl:IsObjDead(para)
        return isDead
    elseif type == 3 then
        local objList = objCtrl:GetTeamBySide(LFightIdleConst.SIDE_B)
        for k,v in ipairs(objList) do
            if not v:IsDeadEnd() then
                return false
            end
        end
        return true
    elseif type == 4 then
        local isDead = objCtrl:IsObjDead(para)
        if not isDead then
            objCtrl:AddClickObjList(para)
            local obj = objCtrl:GetObjByKey(para)
            if obj and obj:IsReady() then
                local pos = objCtrl:GetObjPos(para)
                GF.OpenWnd("UISy",{operType = 4 , pos = pos,objId = para})
            end
        else
            FireEvent(EventNames.ON_STORY_OBJ_HURT,para)
        end
        return isDead
    elseif type == 5 then
        if gModelBattle:IsCombatLifeFinish(LCombatTypeConst.COMBAT_MAIN) then
            local isPass = gModelInstance:IsBattleNodePass(para)
            return isPass
        end
    elseif type == 6 then
        if not gModelBattle:IsLevelUpShowOrWait() then
            return true
        end
    elseif type== 7 then

        if gModelCallHero:IsWaitCallRet() then
            return false
        end

        if gModelCallHero:IsMagicCalled() then
            return true
        else
            local callRef = gModelCallHero:GetCallRefByRefId(ModelCallHero.CALL_TYPE_SPECIAL)
            local expend = callRef.oneExpend
            expend = string.split(expend, "|")
            local payRefId, payNum,haveNum
            if #expend == 1 then
                local data = string.split(expend[1], "=")
                payRefId, payNum = tonumber(data[2]), tonumber(data[3])
                haveNum = gModelItem:GetNumByRefId(payRefId)
            else
                for i, v in ipairs(expend) do
                    local data = string.split(v, "=")
                    local refId, num = tonumber(data[2]), tonumber(data[3])
                    haveNum = gModelItem:GetNumByRefId(refId)
                    if i == 1 and haveNum >= num then
                        payRefId,payNum = refId,num
                        break
                    else
                        payRefId,payNum = refId,num
                    end
                end
            end
            gModelCallHero:OnCallHeroReq(ModelCallHero.CALL_TYPE_SPECIAL,1, payRefId)
            return true
        end
    elseif type == 8 then
        if not gModelPlot:CheckIsOpenCommonTips(para) then
            return true
        end
    end

    return false
end

function LStoryEventCtrl:OnRun(time)

    self:CheckStartEvent(time)

    if not self._storyEventList then
        return
    end
    for k,v in ipairs(self._storyEventList) do
        if not v:IsEnd() then
            v:Run(time)
        end
    end

    self:CheckEndEvent()
end
function LStoryEventCtrl:NotifyHeroLoaded(heroId)
    for k,v in ipairs(self._storyEventList) do
        local type = v:GetEventType()
        if self._heroRelativeEvent[type] then
            v:OnHeroLoaded(heroId)
        end
    end
end

function LStoryEventCtrl:ClearEvent(list)
    for k,v in pairs(list) do
        local event = self._storyEventMap[v]
        if event then
            event:End()
        end
    end
end

function LStoryEventCtrl:ClearAllEvent()
    if not self._storyEventMap then
        return
    end
    for k,v in pairs(self._storyEventMap) do
        local event = v
        if event then
            event:End()
        end
    end

    self._storyEventList ={}
    self._eventDataList ={}
end

function LStoryEventCtrl:RemoveEventByType(eventType)
    if not self._storyEventMap then
        return
    end
    for k,v in pairs(self._storyEventMap) do
        local type = v:GetEventType()
        if type == eventType then
            v:End()
        end
    end
end

function LStoryEventCtrl:IsEventRunning(eventId)
    if not self._storyEventMap then
        return
    end
    for k,v in pairs(self._storyEventMap) do
        local refId = v:GetEventId()
        if refId == eventId and  not v:IsEnd() then
            return true
        end
    end
end

function LStoryEventCtrl:Destroy()
    if self._storyEventList then
        for k,v in ipairs(self._storyEventList) do
            v:Destroy()
        end
    end

    table.removeall(self)
end

function LStoryEventCtrl:GetManager()
    return self._manager
end


return LStoryEventCtrl